        Task<ICreateCounterpartyForAnyAccountApiResponse> CreateCounterpartyForAnyAccountAsync(string bankid, string accountid, string viewid, CreateCounterpartyForAnyAccountRequest createCounterpartyForAnyAccountRequest, System.Threading.CancellationToken cancellationToken = default);

