        /// <returns><see cref="Task"/>&lt;<see cref="ICreateCounterpartyApiResponse"/>&gt;</returns>
        public async Task<ICreateCounterpartyApiResponse?> CreateCounterpartyOrDefaultAsync(string bankid, string accountid, string viewid, CreateCounterpartyForAnyAccountRequest createCounterpartyForAnyAccountRequest, System.Threading.CancellationToken cancellationToken = default)
        {
            try
            {
                return await CreateCounterpartyAsync(bankid, accountid, viewid, createCounterpartyForAnyAccountRequest, cancellationToken).ConfigureAwait(false);
            }
            catch (Exception)
            {
                return null;
            }
        }

