            catch (Exception)
            {
                return null;
            }
        }

        /// <summary>
        /// Get Accounts by Account Routing Regex &lt;p&gt;This endpoint returns an array of accounts matching the provided routing scheme and the routing address regex.&lt;/p&gt; &lt;p&gt;The &lt;code&gt;bank_id&lt;/code&gt; field is optional.&lt;/p&gt; &lt;p&gt;Example of account routing scheme: &lt;code&gt;IBAN&lt;/code&gt;, &lt;code&gt;OBP&lt;/code&gt;, &lt;code&gt;AccountNumber&lt;/code&gt;, ...&lt;br /&gt; Example of account routing address regex: &lt;code&gt;DE175.*&lt;/code&gt;, &lt;code&gt;55897106215-[A-Z]{3}&lt;/code&gt;, ...&lt;/p&gt; &lt;p&gt;This endpoint can be used to retrieve multiples accounts matching a same account routing address pattern.&lt;br /&gt; For example, if you want to link multiple accounts having different currencies, you can create an account&lt;br /&gt; with &lt;code&gt;123456789-EUR&lt;/code&gt; as Account Number and an other account with &lt;code&gt;123456789-USD&lt;/code&gt; as Account Number.&lt;br /&gt; So we can identify the Account Number as &lt;code&gt;123456789&lt;/code&gt;, so to get all the accounts with the same account number&lt;br /&gt; and the different currencies, we can use this body in the request :&lt;/p&gt; &lt;pre&gt;&lt;code&gt;{    &amp;quot;bank_id&amp;quot;: &amp;quot;BANK_ID&amp;quot;,    &amp;quot;account_routing&amp;quot;: {        &amp;quot;scheme&amp;quot;: &amp;quot;AccountNumber&amp;quot;,        &amp;quot;address&amp;quot;: &amp;quot;123456789-[A-Z]{3}&amp;quot;    } } &lt;/code&gt;&lt;/pre&gt; &lt;p&gt;This request will returns the accounts matching the routing address regex (&lt;code&gt;123456789-EUR&lt;/code&gt; and &lt;code&gt;123456789-USD&lt;/code&gt;).&lt;/p&gt; &lt;p&gt;User Authentication is Required. The User must be logged in. The Application must also be authenticated.&lt;/p&gt; &lt;p&gt;&lt;strong&gt;JSON request body fields:&lt;/strong&gt;&lt;/p&gt; &lt;p&gt;&lt;a href&#x3D;\&quot;/glossary#account_routing\&quot;&gt;&lt;strong&gt;account_routing&lt;/strong&gt;&lt;/a&gt;:&lt;/p&gt; &lt;p