        public async Task<IGetTransactionsForBankAccountApiResponse?> GetTransactionsForBankAccountOrDefaultAsync(string bankid, string accountid, string viewid, System.Threading.CancellationToken cancellationToken = default)
        {
            try
            {
                return await GetTransactionsForBankAccountAsync(bankid, accountid, viewid, cancellationToken).ConfigureAwait(false);
            }
            catch (Exception)
            {
                return null;
            }
